import {Link, Navigate, useLoaderData} from 'react-router-dom'
import { useUserContext } from '../context/UserContext';
import {Image, Container,Button} from 'react-bootstrap'
import {Card,Col,Row,Space} from 'antd'
const {Meta } = Card

export default function ApiGet() {
  const {get} = useLoaderData();

  const user = useUserContext();

  if(!user){
    <Navigate to="/" />
  }


  return (
    <div className="container">
      
      <Space direction="vertical" size="middle" style={{ display: 'flex' }}>
      <Row gutter={18}>
      {
        get.length > 0? (
          get.map((data)=>(
            
            <Col span={5} style={{margin:'5px'}}>
              <Card
              hoverable
              style={{width: 240,}}
              cover={<img alt="example" src="https://os.alipayobjects.com/rmsportal/QBnOOoLaAfKPirc.png" />}>
              
              <Link to={`/apiGet/${data._id}`} className='btn btn-outline-primary'>{data.nombreProducto}</Link>
              </Card>
              
            </Col>
           
            
          ))
        ):(
          <p>Sin datos</p>
        )
      }
      </Row >
      </Space>
      
    </div>
  )
}

export const GetData = async () =>{
  try{
    const res = await fetch("https://api-rainbow.vercel.app/api/products")
    const get = await res.json()

    return {get}

  }catch(err){
    console.log(err)
  }
}
