import { useEffect } from 'react';
import Nav from '../components/Nav';
import { useUserContext } from '../context/UserContext'
import { Link, useNavigate, NavLink } from 'react-router-dom';

function About() {


  const showModal =()=>{
    document.getElementById("modal").classList.add("show")
  }

  const hideModal = () =>{
    document.getElementById("modal").classList.remove("show")
  }
  useEffect(() => {
    const projectItems = document.querySelectorAll(".project-item");
    projectItems.forEach((item,i) => {
      item.addEventListener("click", () => {
        if(item.classList.contains("active")){
          item.classList.remove("active")
          alert("Se Activo")
        }else{
          item.classList.add("active")
          alert("Se Apago")
        }
      });
    });
  }, []);


  const navigate = useNavigate();
  const{user,setUser} = useUserContext();
  if(!user){
    navigate("/home")
  }

  return (
    <>
    <div className="container-left">
      <div className="logo-content">
        <div className="logo"></div>
        <h1 style={{marginLeft:'20px'}}>SoftionPro</h1>
      </div>
      <div className="projects-container">
        <div className="projects">
          <ul>
            <li className="project-item">Proyecto 1</li>
            <li className="project-item">Proyecto 2</li>
            <li className="project-item">Proyecto 3</li>
            <li className="project-item">Proyecto 4</li>
          </ul>
        </div>
      </div>
    </div>
    <div className="container-right">
      <div className="nav-container">
        <div className="content-project">
          <h1 style={{color:'#717171'}}>Projecto 01</h1>
          <div> 
            <h1 style={{color:'#3279CB'}}>Realizado</h1>
            <span style={{color:'#717171',fontSize:'20px'}}>Estado</span>
          </div>
          <div>
            <h1 style={{color:'#717171'}}>18 / 10 / 23</h1>
            <span style={{color:'#717171',fontSize:'20px'}}>Inicio</span>
          </div>
          <div>
            <h1 style={{color:'#717171'}}>22 / 12 / 20</h1>
            <span style={{color:'#717171',fontSize:'20px'}}>Finalizado</span>
          </div>
        </div>
        <div className="nav-bar">
          <nav className='nav'>
            <NavLink className="nav-button" to={"/home"} id="navBtn" > 
            <div className="three-bar">
              <span className='bar1'></span>
              <span className='bar2'></span>
              <span className='bar3'></span>
              </div> 
              Proyectos</NavLink>
            <NavLink className="nav-button" to={"/gantt"} id="navBtn" >
            <div className="three-bar">
              <span className='bar1'></span>
              <span className='bar2'></span>
              <span className='bar3'></span>
              </div> Gantt</NavLink>
            <NavLink className="nav-button" to={"/integrantes"} id="navBtn" >Integrantes</NavLink>
          </nav>
        </div>
      </div>
      <div className="content"></div>
    </div>
    </>
  )
}

export default About